module top_module(T, S, R, CLK, obf_Q, QN);input T, S, R, CLK;
  output obf_Q, QN;
  reg obf_Q, QN;

  always @(posedge CLK) begin
    if (S) begin
      obf_Q <= 1;
      QN <= 0;
    end else if (R) begin
      obf_Q <= 0;
      QN <= 1;
    end else if (T) begin
      obf_Q <= ~obf_Q;
      QN <= ~QN;
    end
  end
endmodule
